public class SimpleSwitch {
  public static void main(String[] args) {
    int day = 3;
    switch (day) {
      case 1:
        System.out.println("Bazar ertəsi");
        break;
      case 2:
        System.out.println("Çərşənbə axşamı");
        break;
      case 3:
        System.out.println("Çərşənbə");
        break;
      default:
        System.out.println("Başqa gün");
    }
  }
}
