public class SwitchExpression {
  public static void main(String[] args) {
    int day = 3;
    String dayType = switch (day) {
      case 1, 2, 3, 4, 5 -> "Həftə içi";
      case 6, 7 -> "Həftə sonu";
      default -> "Naməlum gün";
