public class SwitchVsIf {
  public static void main(String[] args) {
    int grade = 85;
    // Switch ilə
    switch (grade / 10) {
      case 9:
      case 10:
        System.out.println("Switch: Əla!");
        break;
      case 8:
        System.out.println("Switch: Yaxşı!");
        break;
      default:
        System.out.println("Switch: Digər!");
    }
    // If-else ilə
    if (grade >= 90) {
      System.out.println("If: Əla!");
    } else if (grade >= 80) {
      System.out.println("If: Yaxşı!");
    } else {
      System.out.println("If: Digər!");
    }
  }
}
// Çıxış: Switch: Yaxşı!
// If: Yaxşı!

