public class SwitchVsIf {
  public static void main(String[] args) {
    int grade = 85;
    // Switch
    switch (grade / 10) {
      case 9:
      case 10:
        System.out.println("Switch: Excellent!");
        break;
      case 8:
        System.out.println("Switch: Good!");
        break;
      default:
        System.out.println("Switch: Other!");
    }
    // If-else
    if (grade >= 90) {
      System.out.println("If: Excellent!");
    } else if (grade >= 80) {
      System.out.println("If: Good!");
    } else {
      System.out.println("If: Other!");
    }
  }
}
// Output: Switch: Good!
// If: Good!

