public class SwitchVsIf {
  public static void main(String[] args) {
    int grade = 85;
    // Switch
    switch (grade / 10) {
      case 9:
      case 10:
        System.out.println("Switch: Отлично!");
        break;
      case 8:
        System.out.println("Switch: Хорошо!");
        break;
      default:
        System.out.println("Switch: Другое!");
    }
    // If-else
    if (grade >= 90) {
      System.out.println("If: Отлично!");
    } else if (grade >= 80) {
      System.out.println("If: Хорошо!");
    } else {
      System.out.println("If: Другое!");
    }
  }
}
// Вывод: Switch: Хорошо!
